<?php
$signpem = <<<EOD
-----BEGIN PRIVATE KEY-----

-----END PRIVATE KEY-----
EOD;
$verifypem = <<<EOD
-----BEGIN PUBLIC KEY-----

-----END PUBLIC KEY-----
EOD;
$data='Test string to sign and verify.';
$binarySignature = "";
$success = openssl_sign($data, $binarySignature, $signpem, OPENSSL_ALGO_SHA256);
if (!$success) {
    throw new Exception("Signing failed: " . openssl_error_string());
}
$transportableSignature = base64_encode($binarySignature);
echo "Signature: " . $transportableSignature;
echo "\n-------------------------\n";
////////////////////////////////////

$binarySignature = base64_decode($transportableSignature);
$result = openssl_verify($data, $binarySignature, $verifypem, OPENSSL_ALGO_SHA256);
if ($result === 1) {
    echo "Success: The data is authentic and intact.";
} elseif ($result === 0) {
    echo "Failed: Data tampered with or signature invalid.";
} else {
    echo "Error checking signature: " . openssl_error_string();
}
//Signature: 

